55→
56→    const stageWidth = useMemo(() => Math.max(240, Math.min(CANVAS_MAX_WIDTH, shellWidth)), [shellWidth]);
57→    const stageHeight = getCanvasStageHeight(stageWidth, parsedCanvasDoc?.meta?.aspectRatio);
