357→export const updateJournalService = async(content, title, journalId, userId, postType = null, canvasDocInput = null) => {
358→    if(!journalId){
359→        console.error('journalid is undefined');
360→        throw {status: 400, error: 'journalId is undefined'}
361→    }
362→
363→    if(!userId){
364→        console.error('userId is undefined')
365→        throw({status: 400, error: 'userId is undefined'})
366→    }
367→
368→    const resolvedRequestedPostType = postType ? normalizePostType(postType) : null;
369→
370→    const {data: existingJournal, error: existingJournalError} = await supabase
371→    .from('journals')
372→    .select('id, user_id, content, title, post_type, canvas_doc')
373→    .eq('id', journalId)
374→    .eq('user_id', userId)
375→    .maybeSingle();
376→
377→    if(existingJournalError){
378→        console.error('failed to fetch existing journal for update', existingJournalError.message);
379→        throw {status: 500, error: 'failed to fetch existing journal for update'};
380→    }
381→
382→    if(!existingJournal){
383→        console.error('journal not found for update');
384→        throw {status: 404, error: 'journal not found for update'};
385→    }
386→
387→    const resolvedPostType = resolvedRequestedPostType || normalizePostType(existingJournal.post_type);
388→    const resolvedTitle = typeof title === 'string' && title.trim() ? title.trim() : existingJournal.title;
389→    if(!resolvedTitle){
390→        console.error('title is undefined');
391→        throw {status: 400, error: 'title is undefined'};
392→    }
393→
394→    let resolvedContent = existingJournal.content;
395→    let resolvedCanvasDoc = existingJournal.canvas_doc;
396→    let embeddingBody = '';
397→
398→    if(resolvedPostType === POST_TYPE_CANVAS){
399→        if(canvasDocInput){
400→            try {
401→                resolvedCanvasDoc = parseCanvasDocInput(canvasDocInput);
402→            } catch (error) {
403→                console.error('invalid canvas doc on update:', error?.message || error);
404→                throw {status: 400, error: 'invalid canvas_doc'};
405→            }
406→        }
407→
408→        if(!resolvedCanvasDoc){
409→            console.error('canvas_doc is missing for canvas post update');
410→            throw {status: 400, error: 'canvas_doc is missing for canvas post update'};
411→        }
412→
413→        resolvedContent = null;
414→        embeddingBody = extractCanvasPlainText(resolvedCanvasDoc);
415→    } else {
416→        if(typeof content === 'string' && content.trim()){
417→            resolvedContent = content;
418→        }
419→
420→        if(!resolvedContent){
421→            console.error('text content is missing for text post update');
422→            throw {status: 400, error: 'text content is missing for text post update'};
423→        }
424→
425→        const parseData = parseTextContentSafely(resolvedContent);
426→        if(!parseData){
427→            console.error('failed to parse text content for update');
428→            throw {status: 400, error: 'failed to parse text content for update'};
429→        }
430→
431→        resolvedCanvasDoc = null;
432→        embeddingBody = parseData.wholeText || '';
433→    }
434→
435→    const embeddings = await GenerateEmbeddings(resolvedTitle, embeddingBody);
436→
437→    const embeddingResult = embeddings;
438→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
439→        console.error('failed to generate embeddings')
440→        throw {status: 400, error: 'failed to generate embeddings'};
441→    }
442→
443→    const journalData = {
444→        content: resolvedContent,
445→        title: resolvedTitle,
446→        post_type: resolvedPostType,
447→        canvas_doc: resolvedCanvasDoc,
448→        embeddings: embeddings
449→    }
450→
451→    const {data, error} = await supabase
452→    .from('journals')
453→    .update(journalData)
454→    .eq('id', journalId)
455→    .eq('user_id', userId)
456→
457→    if(error){
458→        console.error('supabase error while uploading content:', error.message);
459→        throw{status: 500, error: 'supabase error while uploading content'};
460→    }
461→
462→    return true;
463→}
