  28→const GRID_SIZE = 24;
  29→const CANVAS_MAX_WIDTH = 560;
  30→const MOBILE_BREAKPOINT = 820;
  31→const DOODLE_MIN_DISTANCE = 0.004;
  32→const DOODLE_SMOOTH_FACTOR = 0.3;
  33→const MIN_VIEWPORT_SCALE = 0.85;
  34→const MAX_VIEWPORT_SCALE = 3;
  35→const OBJECT_LIFT_MULTIPLIER = 1.03;
  36→
  37→const COLOR_PALETTES = [
  38→    {label: "Pastels", colors: ["#f8c8dc", "#f9e2af", "#b7e4c7", "#bde0fe", "#d7c3ff"]},
  39→    {label: "Earth", colors: ["#8c5e3c", "#b7794b", "#5a6d4d", "#4d6f75", "#2f3e46"]},
  40→    {label: "Neon", colors: ["#ff2d55", "#ff7a00", "#f7ff00", "#00e5ff", "#8a2be2"]}
  41→];
  42→
  43→const DEFAULT_DOODLE_COLOR = COLOR_PALETTES[2].colors[0];
  44→
  45→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
  46→const createId = (prefix) => `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  47→const randomPlacement = () => ({
  48→    rotation: (Math.random() - 0.5) * 10,
  49→    xOffset: (Math.random() - 0.5) * 0.06,
  50→    yOffset: (Math.random() - 0.5) * 0.06
  51→});
  52→
  53→const sanitizeNormalizedPoints = (rawPoints) => {
  54→    if(!Array.isArray(rawPoints)){
  55→        return [];
  56→    }
  57→
  58→    const numericPoints = rawPoints
  59→        .map((point) => Number(point))
  60→        .filter((point) => !Number.isNaN(point))
  61→        .map((point) => clamp(point, 0, 1));
  62→
  63→    if(numericPoints.length < 2){
  64→        return [];
  65→    }
  66→
  67→    return numericPoints.length % 2 === 0 ? numericPoints : numericPoints.slice(0, -1);
  68→};
  69→
  70→const getStageHeight = (width, aspectRatio) => (aspectRatio === "4:5" ? Math.round(width * 1.25) : width);
  71→
  72→const getLegacyFontStyle = (fontStyle) => {
  73→    if(fontStyle === "mono"){
  74→        return "serif";
  75→    }
  76→    return FONT_STYLE_MAP[fontStyle] ? fontStyle : "serif";
  77→};
  78→
  79→const getSnippetMetrics = (snippet, stageWidth) => {
  80→    const sizeScale = Number.isFinite(snippet.sizeScale) ? snippet.sizeScale : 1;
  81→    const styleKey = FONT_STYLE_MAP[snippet.fontStyle] || "serif";
  82→    const baseFontSize = styleKey === "bold" ? 34 : styleKey === "handwritten" ? 32 : 30;
  83→    const fontSize = clamp(baseFontSize * sizeScale, 18, 92);
  84→    const estimatedWidth = Math.max(120, Math.min(stageWidth * 0.78, Math.round((snippet.text.length || 1) * fontSize * 0.58)));
  85→    const charsPerLine = Math.max(8, Math.floor(estimatedWidth / (fontSize * 0.56)));
  86→    const lineCount = Math.max(1, Math.ceil((snippet.text.length || 1) / charsPerLine));
  87→    const height = Math.max(68, Math.round(lineCount * fontSize * 1.14 + 18));
  88→    return {width: estimatedWidth, height, fontSize};
  89→};
  90→
  91→const constrainViewport = (candidate, stageWidth, stageHeight) => {
  92→    const scale = clamp(candidate?.scale || 1, MIN_VIEWPORT_SCALE, MAX_VIEWPORT_SCALE);
  93→    const scaledWidth = stageWidth * scale;
  94→    const scaledHeight = stageHeight * scale;
  95→    let minX = Math.min(0, stageWidth - scaledWidth);
  96→    let maxX = 0;
  97→    let minY = Math.min(0, stageHeight - scaledHeight);
  98→    let maxY = 0;
  99→
 100→    if(scaledWidth <= stageWidth){
 101→        const centeredX = (stageWidth - scaledWidth) / 2;
 102→        minX = centeredX;
 103→        maxX = centeredX;
 104→    }
 105→    if(scaledHeight <= stageHeight){
 106→        const centeredY = (stageHeight - scaledHeight) / 2;
 107→        minY = centeredY;
 108→        maxY = centeredY;
 109→    }
 110→
 111→    return {
 112→        scale,
 113→        x: clamp(candidate?.x || 0, minX, maxX),
 114→        y: clamp(candidate?.y || 0, minY, maxY)
 115→    };
 116→};
 117→
 118→const getTouchGeometry = (nativeEvent, stage) => {
 119→    const touches = nativeEvent?.touches;
 120→    if(!stage || !touches || touches.length < 2){
 121→        return null;
 122→    }
 123→
 124→    const bounds = stage.container()?.getBoundingClientRect();
 125→    if(!bounds){
 126→        return null;
 127→    }
 128→
 129→    const first = touches[0];
 130→    const second = touches[1];
 131→    const firstPoint = {x: first.clientX - bounds.left, y: first.clientY - bounds.top};
 132→    const secondPoint = {x: second.clientX - bounds.left, y: second.clientY - bounds.top};
 133→
 134→    return {
 135→        center: {x: (firstPoint.x + secondPoint.x) / 2, y: (firstPoint.y + secondPoint.y) / 2},
 136→        distance: Math.hypot(secondPoint.x - firstPoint.x, secondPoint.y - firstPoint.y)
 137→    };
 138→};
