 33→    const unavailableBuckets = [...new Set(pages.flatMap((page) => page?.unavailableBuckets ?? []))];
 34→    const hasMedia = mediaItems.length > 0;
 35→
 36→    useEffect(() => {
 37→        if (inView && hasNextPage && !isFetchingNextPage) {
 38→            fetchNextPage();
